import logging
from dataclasses import dataclass
from typing import Dict, List
import unittest

# Configure logging for production observability
logging.basicConfig(level=logging.INFO, format='%(levelname)s: %(message)s')
logger = logging.getLogger(__name__)

class InventoryError(Exception):
    """Base class for inventory exceptions."""
    pass

class ItemNotFoundError(InventoryError):
    """Raised when an item ID does not exist in the inventory."""
    pass

@dataclass
class Item:
    """Data model representing an inventory item."""
    id: str
    name: str
    quantity: int

    def __post_init__(self):
        if self.quantity < 0:
            raise ValueError("Initial quantity cannot be negative.")

class InventoryManager:
    """Controller for managing inventory state and business logic."""

    def __init__(self) -> None:
        self._items: Dict[str, Item] = {}

    def add_item(self, item: Item) -> None:
        """Adds a new item to the inventory."""
        if item.id in self._items:
            raise InventoryError(f"Item with ID {item.id} already exists.")
        self._items[item.id] = item
        logger.info(f"Added item: {item.name} (ID: {item.id})")

    def update_stock(self, item_id: str, delta: int) -> None:
        """Updates stock levels and triggers alerts for low quantities."""
        if item_id not in self._items:
            raise ItemNotFoundError(f"Item ID {item_id} not found.")

        item = self._items[item_id]
        new_quantity = item.quantity + delta

        if new_quantity < 0:
            raise InventoryError(f"Insufficient stock for {item.name}. Current: {item.quantity}, Delta: {delta}")

        item.quantity = new_quantity

        if item.quantity < 5:
            logger.warning(f"LOW STOCK ALERT: {item.name} (ID: {item_id}) is at {item.quantity}")

    def get_low_stock_items(self, threshold: int = 5) -> List[Item]:
        """Returns a list of items below the specified threshold."""
        return [item for item in self._items.values() if item.quantity < threshold]

class TestInventoryManager(unittest.TestCase):
    """Unit tests for InventoryManager."""

    def setUp(self):
        self.manager = InventoryManager()

    def test_add_item(self):
        item = Item("A1", "Widget", 10)
        self.manager.add_item(item)
        self.assertEqual(self.manager._items["A1"], item)

    def test_duplicate_item_error(self):
        self.manager.add_item(Item("A1", "Widget", 10))
        with self.assertRaises(InventoryError):
            self.manager.add_item(Item("A1", "Duplicate", 5))

    def test_update_stock(self):
        self.manager.add_item(Item("A1", "Widget", 10))
        self.manager.update_stock("A1", -6)
        self.assertEqual(self.manager._items["A1"].quantity, 4)

    def test_insufficient_stock_error(self):
        self.manager.add_item(Item("A1", "Widget", 2))
        with self.assertRaises(InventoryError):
            self.manager.update_stock("A1", -5)

    def test_low_stock_threshold(self):
        self.manager.add_item(Item("A1", "Low", 3))
        self.manager.add_item(Item("A2", "High", 10))
        low_items = self.manager.get_low_stock_items(5)
        self.assertEqual(len(low_items), 1)
        self.assertEqual(low_items[0].id, "A1")

if __name__ == "__main__":
    unittest.main()
